args.cypher:
// List all AAS shells in the graph to understand the full landscape
MATCH (aas:AssetAdministrationShell)
RETURN aas.idShort, aas.id ORDER BY aas.idShort

// Get FacilityInformation details for Hall3 and Hall4
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Get FacilityInformation details for Hall4
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// List all AAS shells in the environment
MATCH (aas:AssetAdministrationShell)
RETURN aas.idShort, aas.id ORDER BY aas.idShort

// Find all AAS shells and their assets to identify the transport robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Let me look at the full element structure of the HierarchicalStructures submodel
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.smId

// Check all properties in the Service Request Notification submodel
MATCH (sm:Submodel {id: 'urn:submodel:mir100:001:servicerequestnotification_v2'})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Get the full structure of the Service Request Notification submodel
MATCH (sm:Submodel {id: 'urn:submodel:mir100:001:servicerequestnotification_v2'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.smId, el.idShortPath

// Get all properties from the TechnicalDataAGV submodel
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:technicaldataagv'})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Find all AAS shells and their assets to identify the transport robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind
